const d = $input.first().json;
const recs = {
  'empaste':        'Evita comer por esa zona 2h. Es normal algo de sensibilidad los primeros días.',
  'composite':      'Evita comer por esa zona 2h. Es normal algo de sensibilidad los primeros días.',
  'endodoncia':     'Toma antiinflamatorio si hay molestia. Evita mascar por ese lado hasta poner la corona definitiva.',
  'blanqueamiento': 'Evita café, vino, tabaco y colorantes 48h. Usa pasta para dientes sensibles.',
  'higiene':        'Sigue las instrucciones de cepillado. Usa seda dental o cepillos interproximales cada día.',
  'extraccion':     'Morder la gasa 30 min. No enjuagarse hoy. Dieta blanda 24h. Frío externo si hay inflamación.',
  'implante':       'No fumes las primeras semanas. Cepilla suave alrededor. Controla inflamación con frío externo.',
  'corona':         'La corona puede tardar 24-48h en asentarse. Evita alimentos muy duros los primeros días.',
  'ortodoncia':     'Porta los alineadores/retenedores según indicaciones. Limpia bien alrededor de los brackets.',
};
const trat = (d.tratamiento||'').toLowerCase();
const key = Object.keys(recs).find(k => trat.includes(k)) || null;
const rec = key ? recs[key] : 'Sigue las indicaciones de tu doctor. Contáctanos si tienes alguna duda.';
const msg = `📋 Tras tu *${d.tratamiento||'tratamiento'}*, ${d.nombre}:\n\n${rec}\n\n¡Tu sonrisa te lo agradecerá! 🦷 Estamos aquí si necesitas algo.`;
return [{ json: { ...d, mensaje: msg } }];
